104	int identityResponse(void **msg, nr_user_nas_t *UE) {
105	  if (UE->uicc == NULL)
106	    // config file section hardcoded as "uicc", nevertheless it opens to manage several UEs or a multi SIM UE
107	    UE->uicc=init_uicc("uicc");
108	
109	  // TS 24.501 9.11.3.4
110	  int imsiL=strlen(UE->uicc->imsiStr);
111	  int msinL=imsiL-3-UE->uicc->nmc_size;
112	  int respSize=sizeof(IdentityresponseIMSI_t) + (msinL+1)/2;
113	  IdentityresponseIMSI_t *resp=(IdentityresponseIMSI_t *) calloc(respSize,1);
114	  resp->common.epd=SGSmobilitymanagementmessages;
115	  resp->common.sh=0;
116	  resp->common.mt=Identityresponse;
117	  resp->common.len=htons(respSize-sizeof(Identityresponse_t));
118	  resp->mi=SUCI;
119	  resp->mcc1=UE->uicc->imsiStr[0]-'0';
120	  resp->mcc2=UE->uicc->imsiStr[1]-'0';
121	  resp->mcc3=UE->uicc->imsiStr[2]-'0';
122	  resp->mnc1=UE->uicc->imsiStr[3]-'0';
123	  resp->mnc2=UE->uicc->imsiStr[4]-'0';
124	  resp->mnc3=UE->uicc->nmc_size==2? 0xF : UE->uicc->imsiStr[3]-'0';
125	  // TBD: routing to fill (FF ?)
126	  char *out=(char *)(resp+1);
127	  char *ptr=UE->uicc->imsiStr + 3 + UE->uicc->nmc_size;
128	
129	  while ( ptr < UE->uicc->imsiStr+strlen(UE->uicc->imsiStr) ) {
130	    *out=((*(ptr+1)-'0')<<4) | (*(ptr) -'0');
131	    out++;
132	    ptr+=2;
133	  }
134	
135	  if (msinL%2 == 1)
136	    *out=((*(ptr-1)-'0')) | 0xF0;
137	
138	  *msg=resp;
139	  return respSize;
140	}
