142	int authenticationResponse(void **msg,nr_user_nas_t *UE) {
143	  if (UE->uicc == NULL)
144	    // config file section hardcoded as "uicc", nevertheless it opens to manage several UEs or a multi SIM UE
145	    UE->uicc=init_uicc("uicc");
146	
147	  myCalloc(resp, authenticationresponse_t);
148	  resp->epd=SGSmobilitymanagementmessages;
149	  resp->sh=0;
150	  resp->mt=Authenticationresponse;
151	  resp->iei=IEI_AuthenticationResponse;
152	  resp->RESlen=sizeof(resp->RES); // always 16 see TS 24.501 Table 8.2.2.1.1
153	  // Verify the AUTN
154	  // a full implementation need to test several SQN
155	  // as the last 5bits can be any value
156	  // and the value can also be greater and accepted (if it is in the accepted window)
157	  uint8_t AUTN[16];
158	  uicc_milenage_generate(AUTN, UE->uicc);
159	
160	  if ( memcmp(UE->uicc->autn, AUTN, sizeof(AUTN)) == 0 ) {
161	    // prepare and send good answer
162	    resToresStar(resp->RES,UE->uicc);
163	  } else {
164	    // prepare and send autn is not compatible with our data
165	    abort();
166	  }
167	
168	  *msg=resp;
169	  return sizeof(authenticationresponse_t);
170	}
