void SGSauthenticationReject(void *msg, nr_ue_nas_t *UE) {
  LOG_I(NAS, "Received Authentication Reject message\n");

  // Stop all running 5GMM timers to prevent race conditions
  _stop_all_running_timers(UE);

  // Clear security context as specified in 3GPP TS 24.501 Section 5.4.2.5
  if (UE && UE->security_container) {
    LOG_I(NAS, "Clearing security context after authentication reject\n");
    memset(&UE->security, 0, sizeof(UE->security));
